sql:
SELECT AVG(human_score) AS average_human_score, AVG(ai_score) AS average_ai_score
FROM game_results
WHERE game_type = 'rps';

SELECT game_id, game_type, human_wins, ai_wins 
FROM game_results 
ORDER BY human_wins DESC, ai_wins DESC;

external_knowledge:
- 'Key personnel' refers to staff with roles of 'researcher' or 'admin'; 
- 'Challenging' games are those with a difficulty level between 50 and 100;
- 'Decent amount of activity' is defined as games with over 10 rounds and lasting between 30 to 120 seconds;
- 'Past month' is specified as July 2023;
- 'Decent amount of specific measurements noted' means more than five unique metrics.

